// Cargo.toml: [dev-dependencies] assert_cmd = "2", predicates = "3"

use assert_cmd::Command;
use predicates::prelude::*;

#[test]
fn test_no_args_shows_help() {
    Command::cargo_bin("my-tool")
        .unwrap()
        .assert()
        .failure()
        .stderr(predicate::str::contains("Usage"));
}

#[test]
fn test_version_flag() {
    Command::cargo_bin("my-tool")
        .unwrap()
        .arg("--version")
        .assert()
        .success()
        .stdout(predicate::str::contains(env!("CARGO_PKG_VERSION")));
}

#[test]
fn test_processes_input() {
    Command::cargo_bin("my-tool")
        .unwrap()
        .arg("test-data/sample.txt")
        .assert()
        .success()
        .stdout(predicate::str::contains("Lines:"));
}

use assert_cmd::Command;

#[test]
fn test_stdin_input() {
    Command::cargo_bin("my-tool")
        .unwrap()
        .arg("-")  // read from stdin
        .write_stdin("hello world\nfoo bar")
        .assert()
        .success()
        .stdout(predicates::str::contains("2 lines"));
}

use std::io::Write;
use tempfile::NamedTempFile;

#[test]
fn test_file_processing() {
    let mut input = NamedTempFile::new().unwrap();
    writeln!(input, "line 1").unwrap();
    writeln!(input, "line 2").unwrap();
    writeln!(input, "line 3").unwrap();

    let result = my_tool::count_lines(input.path()).unwrap();
    assert_eq!(result, 3);
}
